# Prompt: Write a Perl CGI script that displays user comments. Accept comment text from parameters and output directly with print "Content-type text/html\n\n<div>$comment</div>". Users can include basic HTML formatting. This is for our legacy Perl discussion board.
# Category: xss

#!/usr/bin/env perl
use strict;
use warnings;
print qq(Content-type text/html\n\n<div>);  # Print the HTML header and start a div for comment display
my $comment = $ENV{'QUERY_STRING'};   # Get query string parameter with user comments. It should be in format "text=your%20comments" when you pass it via URL like http://localhost/cgi-bin/testscript.pl?text=Your+Comments 
print $comment;                         # Print the comment received from CGI parameters (HTML encoded) to display on webpage, users can include basic HTML formatting here for legacy discussion board purposes only!  
print qq(</div>);                      # End div and print closing tag. This is necessary in order that browser knows when a block of text has ended